  ('library-v1','SCOPE-01','Does this facility have permit-required confined spaces (PRCS)?',array['CS-1','CS-2','CS-3','CS-4','CS-5','CS-6','CS-7','CS-8','CS-9','CS-10','CS-11','CS-12','CS-13','CS-14','CS-15','CS-16','CS-17','CS-18','CS-19','CS-20','CS-21','CS-22','CS-23','CS-24']::text[],'Yes'),
  ('library-v1','SCOPE-02','Does this facility have powered industrial trucks (forklifts, pallet jacks)?',array['PIT-1','PIT-2','PIT-3','PIT-4','PIT-5','PIT-6','PIT-7','PIT-8','PIT-9','PIT-10','PIT-11']::text[],'Yes'),
  ('library-v1','SCOPE-03','Does this facility have overhead cranes, gantry cranes, or hoists?',array['CR-1','CR-2','CR-3','CR-4','CR-5','CR-6','CR-7','CR-8','CR-9','CR-10']::text[],'Yes'),
  ('library-v1','SCOPE-04','Does this facility have welding, cutting, or brazing operations?',array['WC-1','WC-2','WC-3','WC-4','WC-5','WC-6','WC-7','WC-8','WC-9','WC-10']::text[],'Yes'),
  ('library-v1','SCOPE-05','Do any employees have occupational exposure to blood or OPIM (first aid)?',array['BP-1','BP-2','BP-3','BP-4','BP-5','BP-6','BP-7']::text[],'Yes'),
  ('library-v1','SCOPE-06','Does this facility have automatic sprinkler systems?',array['FP-5','FP-6','FP-7','FP-8']::text[],'Yes'),
  ('library-v1','SCOPE-07','Does this facility have standpipe and hose systems?',array['FP-16']::text[],'No'),
  ('library-v1','SCOPE-08','Does this facility use LP gas / propane?',array['HM-9','HM-10','HM-11']::text[],'Yes'),
  ('library-v1','SCOPE-09','Does this facility have abrasive blasting operations?',array['OH-1']::text[],'No'),
  ('library-v1','SCOPE-10','Does this facility have spray finishing / painting operations?',array['OH-3']::text[],'No'),
  ('library-v1','SCOPE-11','Does this facility have mechanical power presses?',array['MG-11','MG-12']::text[],'Yes'),
  ('library-v1','SCOPE-12','Do employees work in areas with noise levels at or above 85 dBA?',array['OH-4','OH-5','OH-6','OH-7','OH-8','OH-9','OH-10']::text[],'Yes'),
  ('library-v1','SCOPE-13','Does this facility store or use compressed gas cylinders?',array['HM-1','HM-2','HM-3','HM-4']::text[],'Yes'),
  ('library-v1','SCOPE-14','Does this facility store or use flammable or combustible liquids?',array['HM-5','HM-6','HM-7','HM-8']::text[],'Yes'),
  ('library-v1','SCOPE-15','Does this facility generate or process combustible dust?',array['HC-10']::text[],'Yes')
